# action_tracker.py — track open decisions and actions across status reports

from dataclasses import dataclass, field
from typing import Optional, List
from datetime import date

@dataclass
class ProgrammeAction:
    id: str
    description: str
    owner: str
    due_date: date
    status: str = "open"  # open | in_progress | completed | cancelled
    completion_note: Optional[str] = None
    report_opened: str = ""   # report ID where this was first raised
    report_closed: Optional[str] = None

    def close(self, note: str, report_id: str) -> None:
        self.status = "completed"
        self.completion_note = note
        self.report_closed = report_id

@dataclass
class ProgrammeDecision:
    id: str
    question: str
    decision_maker: str
    required_by: date
    status: str = "pending"  # pending | made | deferred | cancelled
    decision_made: Optional[str] = None
    rationale: Optional[str] = None

@dataclass
class StatusReportFeedback:
    report_id: str
    open_actions: List[ProgrammeAction] = field(default_factory=list)
    open_decisions: List[ProgrammeDecision] = field(default_factory=list)

    def carry_forward(self, previous: 'StatusReportFeedback') -> None:
        for action in previous.open_actions:
            if action.status in ("open", "in_progress"):
                self.open_actions.append(action)
        for decision in previous.open_decisions:
            if decision.status == "pending":
                self.open_decisions.append(decision)

    def overdue_items(self, as_of: date) -> dict:
        overdue_actions = [a for a in self.open_actions if a.due_date < as_of and a.status != "completed"]
        overdue_decisions = [d for d in self.open_decisions if d.required_by < as_of and d.status == "pending"]
        return {"actions": overdue_actions, "decisions": overdue_decisions}
